select 
from template
where deleted = 0

    and project_id = #{projectId}


    and project_id in

        #{projectIdItem}



    and template_category = #{templateCategory}


    and template_type = #{templateType}


    and status = #{status}


    and (template_name like concat('%', #{keyword}, '%')
         or scenario like concat('%', #{keyword}, '%'))

order by created_at desc, id desc
